function stripHtmlTags(html: string): string {
  let result = '';
  let i = 0;
  while (i < html.length) {
    if (html[i] === '<') {
      i++;
      while (i < html.length && html[i] !== '>') {
        if (html[i] === '"') {
          i++;
          while (i < html.length && html[i] !== '"') i++;
          if (i < html.length) i++;
        } else if (html[i] === "'") {
          i++;
          while (i < html.length && html[i] !== "'") i++;
          if (i < html.length) i++;
        } else {
          i++;
        }
      }
      i++;
    } else {
      result += html[i];
      i++;
    }
  }
  return result;
}
